form:Form.form:Scripts:
		var pantXML;

function EnabledControls()
{ 
	var l_eva2=(Ctrl("l_eva2").GetXValue()=="1"?true:false);   
	var l_eva3=(Ctrl("l_eva3").GetXValue()=="1"?true:false);
	var l_pree=(Ctrl("l_pree").GetXValue()=="1"?true:false);      
	var l_aux;

	if(Ctrl("d_reporte").GetXValue()=="")
	{        
		CtrlEnabled("l_mostrar_res"    ,false);

		//Plantilla
		CtrlEnabled("e_show_show"      ,false);
		CtrlEnabled("e_preeval_show"   ,false);
		CtrlEnabled("e_evaluador_show" ,false);
		CtrlEnabled("e_evaluado_show"  ,false);
		CtrlEnabled("e_supervisor_show",false);
		CtrlEnabled("e_aprobacion_show",false);
		CtrlEnabled("e_posaprob_show"  ,false);

		//Editable
		CtrlEnabled("e_show_edit"      ,false);
		CtrlEnabled("e_preeval_edit"   ,false);
		CtrlEnabled("e_evaluador_edit" ,false);
		CtrlEnabled("e_evaluado_edit"  ,false);
		CtrlEnabled("e_supervisor_edit",false);
		CtrlEnabled("e_aprobacion_edit",false);
		CtrlEnabled("e_posaprob_edit"  ,false);

		//Evaluador
		CtrlEnabled("e_show_eval"      ,false);
		CtrlEnabled("e_preeval_eval"   ,false);
		CtrlEnabled("e_evaluador_eval" ,false);
		CtrlEnabled("e_evaluado_eval"  ,false);
		CtrlEnabled("e_supervisor_eval",false);
		CtrlEnabled("e_aprobacion_eval",false);
		CtrlEnabled("e_posaprob_eval"  ,false);

		//Autoevaluacion
		CtrlEnabled("e_show_auto"      ,false);
		CtrlEnabled("e_preeval_auto"   ,false);
		CtrlEnabled("e_evaluador_auto" ,false);
		CtrlEnabled("e_evaluado_auto"  ,false);
		CtrlEnabled("e_supervisor_auto",false);
		CtrlEnabled("e_aprobacion_auto",false);
		CtrlEnabled("e_posaprob_auto"  ,false);

		//Supervisor
		CtrlEnabled("e_show_super"      ,false);
		CtrlEnabled("e_preeval_super"   ,false);
		CtrlEnabled("e_evaluador_super" ,false);
		CtrlEnabled("e_evaluado_super"  ,false);
		CtrlEnabled("e_supervisor_super",false);
		CtrlEnabled("e_aprobacion_super",false);
		CtrlEnabled("e_posaprob_super"  ,false);

		//Comentarios
		CtrlEnabled("e_show_coment"      ,false);
		CtrlEnabled("e_preeval_coment"   ,false);
		CtrlEnabled("e_evaluador_coment" ,false);
		CtrlEnabled("e_evaluado_coment"  ,false);
		CtrlEnabled("e_supervisor_coment",false);
		CtrlEnabled("e_aprobacion_coment",false);
		CtrlEnabled("e_posaprob_coment"  ,false);             

		//Parametros
		Ctrl("lbl_d_cus1").SetText("Parametro 1");
		Ctrl("lbl_d_cus2").SetText("Parametro 2");
		Ctrl("lbl_d_cus3").SetText("Parametro 3");
		Ctrl("lbl_d_cus4").SetText("Parametro 4");
		Ctrl("lbl_d_cus5").SetText("Parametro 5");
	} else
	{                
		rep=pantXML.FindElement2("OPT","value",Ctrl("d_reporte").GetXValue()).GetAttr("impl");                      

		if (rep=="")
		{           
			CtrlEnabled("l_mostrar_res", true);

			//Plantilla                      
			CtrlSetValue("e_show_show"      , false, "1");
			CtrlSetValue("e_preeval_show"   , false, "0");
			CtrlSetValue("e_evaluador_show" , false, "1");
			CtrlSetValue("e_evaluado_show"  , false, "0");
			CtrlSetValue("e_supervisor_show", false, "0");
			CtrlSetValue("e_aprobacion_show", false, "1");
			CtrlSetValue("e_posaprob_show"  , false, "1");

			//Editable
			CtrlSetValue("e_show_edit"      , false,  "0");
			CtrlSetValue("e_preeval_edit"   , false,  "0");
			CtrlSetValue("e_evaluador_edit" , false,  "1");
			CtrlSetValue("e_evaluado_edit"  , false,  "0");
			CtrlSetValue("e_supervisor_edit", false,  "0");
			CtrlSetValue("e_aprobacion_edit", false,  "0");
			CtrlSetValue("e_posaprob_edit"  , false,  "0");

			//Evaluador                
			CtrlSetValue("e_show_eval"      , false, "1");
			CtrlSetValue("e_preeval_eval"   , false, "0");
			CtrlSetValue("e_evaluador_eval" , false, "2");
			CtrlSetValue("e_evaluado_eval"  , false, "0");
			CtrlSetValue("e_supervisor_eval", false, "0");
			CtrlSetValue("e_aprobacion_eval", false, "1");
			CtrlSetValue("e_posaprob_eval"  , false, "1");

			//Autoevaluacion
			CtrlSetValue("e_show_auto"      , false, "0");
			CtrlSetValue("e_preeval_auto"   , false, "0");
			CtrlSetValue("e_evaluador_auto" , false, "0");
			CtrlSetValue("e_evaluado_auto"  , false, "0");
			CtrlSetValue("e_supervisor_auto", false, "0");
			CtrlSetValue("e_aprobacion_auto", false, "0");
			CtrlSetValue("e_posaprob_auto"  , false, "0");

			//Supervisor
			CtrlSetValue("e_show_super"      , false, "0");
			CtrlSetValue("e_preeval_super"   , false, "0");
			CtrlSetValue("e_evaluador_super" , false, "0");
			CtrlSetValue("e_evaluado_super"  , false, "0");
			CtrlSetValue("e_supervisor_super", false, "0");
			CtrlSetValue("e_aprobacion_super", false, "0");
			CtrlSetValue("e_posaprob_super"  , false, "0");

			//Comentarios
			CtrlSetValue("e_show_coment"      , false, "1");
			CtrlSetValue("e_preeval_coment"   , false, "0");
			CtrlSetValue("e_evaluador_coment" , false, "1");
			CtrlSetValue("e_evaluado_coment"  , false, "0");
			CtrlSetValue("e_supervisor_coment", false, "0");
			CtrlSetValue("e_aprobacion_coment", false, "2");
			CtrlSetValue("e_posaprob_coment"  , false, "1");        
		} else                             
		{    
			CtrlEnabled("l_mostrar_res", false);
			Ctrl("l_mostrar_res").SetXValue(rep.substr(5,1)=="S"?"1":"0");

			//Plantilla                      
			CtrlSetValue("e_show_show"      , true  , "1");
			CtrlSetValue("e_preeval_show"   , l_pree, "0");
			CtrlSetValue("e_evaluador_show" , true  , "1");
			CtrlSetValue("e_evaluado_show"  , l_eva2, "0");
			CtrlSetValue("e_supervisor_show", l_eva3, "0");
			CtrlSetValue("e_aprobacion_show", true  , "1");
			CtrlSetValue("e_posaprob_show"  , true  , "1");

			//Editable
			l_aux=(rep.substr(0,1)=="E");
			CtrlSetValue("e_show_edit"      , (Ctrl("e_show_show"      ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_preeval_edit"   , (Ctrl("e_preeval_show"   ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador_edit" , (Ctrl("e_evaluador_show" ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluado_edit"  , (Ctrl("e_evaluado_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_supervisor_edit", (Ctrl("e_supervisor_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_aprobacion_edit", (Ctrl("e_aprobacion_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_posaprob_edit"  , (Ctrl("e_posaprob_show"  ).GetXValue()=="1" && l_aux?true:false), "0");

			//Evaluador                
			l_aux=(rep.substr(1,1)=="E");
			CtrlSetValue("e_show_eval"      , (Ctrl("e_show_show"      ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_preeval_eval"   , (Ctrl("e_preeval_show"   ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador_eval" , (Ctrl("e_evaluador_show" ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluado_eval"  , (Ctrl("e_evaluado_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_supervisor_eval", (Ctrl("e_supervisor_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_aprobacion_eval", (Ctrl("e_aprobacion_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_posaprob_eval"  , (Ctrl("e_posaprob_show"  ).GetXValue()=="1" && l_aux?true:false), "0");

			//Autoevaluacion
			l_aux=(rep.substr(2,1)=="A");
			CtrlSetValue("e_show_auto"      , (Ctrl("e_show_show"      ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_preeval_auto"   , (Ctrl("e_preeval_show"   ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_evaluador_auto" , (Ctrl("e_evaluador_show" ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_evaluado_auto"  , (Ctrl("e_evaluado_show"  ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_supervisor_auto", (Ctrl("e_supervisor_show").GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_aprobacion_auto", (Ctrl("e_aprobacion_show").GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_posaprob_auto"  , (Ctrl("e_posaprob_show"  ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");

			//Supervisor
			l_aux=(rep.substr(3,1)=="S");
			CtrlSetValue("e_show_super"      , (Ctrl("e_show_show"      ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_preeval_super"   , (Ctrl("e_preeval_show"   ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_evaluador_super" , (Ctrl("e_evaluador_show" ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_evaluado_super"  , (Ctrl("e_evaluado_show"  ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_supervisor_super", (Ctrl("e_supervisor_show").GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_aprobacion_super", (Ctrl("e_aprobacion_show").GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_posaprob_super"  , (Ctrl("e_posaprob_show"  ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");

			//Comentarios
			l_aux=(rep.substr(4,1)=="C");
			CtrlSetValue("e_show_coment"      , (Ctrl("e_show_show"      ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_preeval_coment"   , (Ctrl("e_preeval_show"   ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador_coment" , (Ctrl("e_evaluador_show" ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluado_coment"  , (Ctrl("e_evaluado_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_supervisor_coment", (Ctrl("e_supervisor_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_aprobacion_coment", (Ctrl("e_aprobacion_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_posaprob_coment"  , (Ctrl("e_posaprob_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
		}

		//Parametros         
		rep=pantXML.FindElement2("OPT","value",Ctrl("d_reporte").GetXValue()).GetAttr("param1"); Ctrl("lbl_d_cus1").SetText(rep==""?"Parametro 1":rep);
		rep=pantXML.FindElement2("OPT","value",Ctrl("d_reporte").GetXValue()).GetAttr("param2"); Ctrl("lbl_d_cus2").SetText(rep==""?"Parametro 2":rep);
		rep=pantXML.FindElement2("OPT","value",Ctrl("d_reporte").GetXValue()).GetAttr("param3"); Ctrl("lbl_d_cus3").SetText(rep==""?"Parametro 3":rep);
		rep=pantXML.FindElement2("OPT","value",Ctrl("d_reporte").GetXValue()).GetAttr("param4"); Ctrl("lbl_d_cus4").SetText(rep==""?"Parametro 4":rep);
		rep=pantXML.FindElement2("OPT","value",Ctrl("d_reporte").GetXValue()).GetAttr("param5"); Ctrl("lbl_d_cus5").SetText(rep==""?"Parametro 5":rep);
	}
}      

function CtrlSetValue(Name, enabled, value)
{                
	var ct=Ctrl(Name);

	ct.SetEnabled(enabled);
	if (!enabled) ct.SetXValue(value);
}

function GetCalculateStatus(Name)
{
	var valor=0;      

	valor+=parseInt(Ctrl(Name+"_edit"  ).GetXValue(), 10)*1;
	valor+=parseInt(Ctrl(Name+"_eval"  ).GetXValue(), 10)*2;
	valor+=parseInt(Ctrl(Name+"_auto"  ).GetXValue(), 10)*8;
	valor+=parseInt(Ctrl(Name+"_super" ).GetXValue(), 10)*32;
	valor+=parseInt(Ctrl(Name+"_coment").GetXValue(), 10)*128;
	valor+=parseInt(Ctrl(Name+"_show"  ).GetXValue(), 10)*512;
	return ""+valor;
}  

function ChangeShow() { Ctrl("e_show").SetXValue(GetCalculateStatus("e_show")); }
function ChangeShowShow() { EnabledControls(); Ctrl("e_show").SetXValue(GetCalculateStatus("e_show")); }

function ChangePreEval() { Ctrl("e_preeval").SetXValue(GetCalculateStatus("e_preeval")); }
function ChangePreEvalShow() { EnabledControls(); Ctrl("e_preeval").SetXValue(GetCalculateStatus("e_preeval")); }

function ChangeEvaluador() { Ctrl("e_evaluador").SetXValue(GetCalculateStatus("e_evaluador")); }
function ChangeEvaluadorShow() { EnabledControls(); Ctrl("e_evaluador").SetXValue(GetCalculateStatus("e_evaluador")); }

function ChangeEvaluado() { Ctrl("e_evaluado").SetXValue(GetCalculateStatus("e_evaluado")); }
function ChangeEvaluadoShow() { EnabledControls(); Ctrl("e_evaluado").SetXValue(GetCalculateStatus("e_evaluado")); }

function ChangeSupervisor() { Ctrl("e_supervisor").SetXValue(GetCalculateStatus("e_supervisor")); }
function ChangeSupervisorShow() { EnabledControls(); Ctrl("e_supervisor").SetXValue(GetCalculateStatus("e_supervisor")); }

function ChangeAprobacion() { Ctrl("e_aprobacion").SetXValue(GetCalculateStatus("e_aprobacion")); }
function ChangeAprobacionShow() { EnabledControls(); Ctrl("e_aprobacion").SetXValue(GetCalculateStatus("e_aprobacion")); }

function ChangePosaprob() { Ctrl("e_posaprob").SetXValue(GetCalculateStatus("e_posaprob")); }
function ChangePosaprobShow() { EnabledControls(); Ctrl("e_posaprob").SetXValue(GetCalculateStatus("e_posaprob")); }



function GetEvalEstado(Name, lev1, lev2)
{                                               
	if (Ctrl(Name).GetXValue()=="") return "0";

	if (parseInt(Ctrl(Name).GetXValue(),10) & lev2) return "2";
	if (parseInt(Ctrl(Name).GetXValue(),10) & lev1) return "1";
	return "0";
}

function OnLoad()
{
	if (Ctrl("LIST"))
	{
		RefreshClick();
	} else
	{       
		CtrlEnabled("OBJETIVOS",Ctrl("c_tipo_plantilla").GetXValue()=="F"?true:false);
		CtrlEnabled("LISTAS"   ,Ctrl("c_tipo_plantilla").GetXValue().substr(0,4)=="LST_"?true:false);

		if (Ctrl("main").GetLastDoc("RS-FORMATOS")!=null)
		{
			Ctrl("d_reporte").setOptions(Ctrl("main").GetLastDoc("RS-FORMATOS"));
			Ctrl("d_reporte").SyncHTML();

			pantXML=new NomadXML(Ctrl("main").GetLastDoc("RS-FORMATOS"));
		}


		//Editable
		Ctrl("e_show_show"      ).SetXValue(GetEvalEstado("e_show"      ,512,0));
		Ctrl("e_preeval_show"   ).SetXValue(GetEvalEstado("e_preeval"   ,512,0));
		Ctrl("e_evaluador_show" ).SetXValue(GetEvalEstado("e_evaluador" ,512,0));
		Ctrl("e_evaluado_show"  ).SetXValue(GetEvalEstado("e_evaluado"  ,512,0));
		Ctrl("e_supervisor_show").SetXValue(GetEvalEstado("e_supervisor",512,0));
		Ctrl("e_aprobacion_show").SetXValue(GetEvalEstado("e_aprobacion",512,0));
		Ctrl("e_posaprob_show"  ).SetXValue(GetEvalEstado("e_posaprob"  ,512,0));

		//Editable
		Ctrl("e_show_edit"      ).SetXValue(GetEvalEstado("e_show"      ,1,0));
		Ctrl("e_preeval_edit"   ).SetXValue(GetEvalEstado("e_preeval"   ,1,0));
		Ctrl("e_evaluador_edit" ).SetXValue(GetEvalEstado("e_evaluador" ,1,0));
		Ctrl("e_evaluado_edit"  ).SetXValue(GetEvalEstado("e_evaluado"  ,1,0));
		Ctrl("e_supervisor_edit").SetXValue(GetEvalEstado("e_supervisor",1,0));
		Ctrl("e_aprobacion_edit").SetXValue(GetEvalEstado("e_aprobacion",1,0));
		Ctrl("e_posaprob_edit"  ).SetXValue(GetEvalEstado("e_posaprob"  ,1,0));

		//Evaluador
		Ctrl("e_show_eval"      ).SetXValue(GetEvalEstado("e_show"      ,2,4));
		Ctrl("e_preeval_eval"   ).SetXValue(GetEvalEstado("e_preeval"   ,2,4));
		Ctrl("e_evaluador_eval" ).SetXValue(GetEvalEstado("e_evaluador" ,2,4));
		Ctrl("e_evaluado_eval"  ).SetXValue(GetEvalEstado("e_evaluado"  ,2,4));
		Ctrl("e_supervisor_eval").SetXValue(GetEvalEstado("e_supervisor",2,4));
		Ctrl("e_aprobacion_eval").SetXValue(GetEvalEstado("e_aprobacion",2,4));
		Ctrl("e_posaprob_eval"  ).SetXValue(GetEvalEstado("e_posaprob"  ,2,4));

		//Autoevaluacion
		Ctrl("e_show_auto"      ).SetXValue(GetEvalEstado("e_show"      ,8,16));
		Ctrl("e_preeval_auto"   ).SetXValue(GetEvalEstado("e_preeval"   ,8,16));
		Ctrl("e_evaluador_auto" ).SetXValue(GetEvalEstado("e_evaluador" ,8,16));
		Ctrl("e_evaluado_auto"  ).SetXValue(GetEvalEstado("e_evaluado"  ,8,16));
		Ctrl("e_supervisor_auto").SetXValue(GetEvalEstado("e_supervisor",8,16));
		Ctrl("e_aprobacion_auto").SetXValue(GetEvalEstado("e_aprobacion",8,16));
		Ctrl("e_posaprob_auto"  ).SetXValue(GetEvalEstado("e_posaprob"  ,8,16));

		//Supervisor
		Ctrl("e_show_super"      ).SetXValue(GetEvalEstado("e_show"      ,32,64));
		Ctrl("e_preeval_super"   ).SetXValue(GetEvalEstado("e_preeval"   ,32,64));
		Ctrl("e_evaluador_super" ).SetXValue(GetEvalEstado("e_evaluador" ,32,64));
		Ctrl("e_evaluado_super"  ).SetXValue(GetEvalEstado("e_evaluado"  ,32,64));
		Ctrl("e_supervisor_super").SetXValue(GetEvalEstado("e_supervisor",32,64));
		Ctrl("e_aprobacion_super").SetXValue(GetEvalEstado("e_aprobacion",32,64));
		Ctrl("e_posaprob_super"  ).SetXValue(GetEvalEstado("e_posaprob"  ,32,64));

		//Habilitar los controles		                  
		Ctrl("e_show_coment"      ).SetXValue(GetEvalEstado("e_show"      ,128,256));
		Ctrl("e_preeval_coment"   ).SetXValue(GetEvalEstado("e_preeval"   ,128,256));
		Ctrl("e_evaluador_coment" ).SetXValue(GetEvalEstado("e_evaluador" ,128,256));
		Ctrl("e_evaluado_coment"  ).SetXValue(GetEvalEstado("e_evaluado"  ,128,256));
		Ctrl("e_supervisor_coment").SetXValue(GetEvalEstado("e_supervisor",128,256));
		Ctrl("e_aprobacion_coment").SetXValue(GetEvalEstado("e_aprobacion",128,256));
		Ctrl("e_posaprob_coment"  ).SetXValue(GetEvalEstado("e_posaprob"  ,128,256));

		EnabledControls();
	}    
}

function RefreshClick()
{  
	CtrlEnabled("OBJETIVOS",Ctrl("LIST").GetSelectAttrValue("c_tipo_plantilla")=="F"?true:false);
	CtrlEnabled("LISTAS"   ,Ctrl("LIST").GetSelectAttrValue("c_tipo_plantilla").substr(0,4)=="LST_"?true:false);
}
